:root {
  --panel-bg: #1e1e2e;
  --panel-border: #313145;
  --header-text: #e0e0f0;
  --subtext: #8888aa;
  --accent: #7c6af7;
  --accent-light: #a99df9;
  --room-bg: #2a2a3e;
  --room-active-bg: #7c6af7;
  --room-active-text: #ffffff;
  --room-text: #8888aa;
  --device-bg: #2a2a3e;
  --device-on-bg: #32324a;
  --device-on-border: #7c6af7;
  --device-off-border: #313145;
  --device-name: #c8c8e0;
  --device-value-on: #a99df9;
  --device-value-off: #555570;
  --toggle-off-bg: #3a3a52;
  --toggle-on-bg: #7c6af7;
  --toggle-knob: #ffffff;
  --footer-bg: #252538;
  --stat-label: #8888aa;
  --stat-value: #c8c8e0;
  --dot-color: #4caf82;
}

.panel {
  background: var(--panel-bg);
  border: 1px solid var(--panel-border);
  border-radius: 16px;
  width: 500px;
  padding: 20px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.panel-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.panel-title {
  font-size: 18px;
  font-weight: 700;
  color: var(--header-text);
  letter-spacing: 0.3px;
}

.status-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--dot-color);
}

.rooms {
  display: flex;
  gap: 8px;
}

.room {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  padding: 8px 6px;
  background: var(--room-bg);
  border-radius: 10px;
  cursor: pointer;
}

.room.active {
  background: var(--room-active-bg);
}

.room-icon {
  font-size: 18px;
  line-height: 1;
}

.room-name {
  font-size: 11px;
  font-weight: 600;
  color: var(--room-text);
}

.room.active .room-name {
  color: var(--room-active-text);
}

.devices {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 10px;
}

.device-card {
  background: var(--device-bg);
  border: 1px solid var(--device-off-border);
  border-radius: 12px;
  padding: 12px 10px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.device-card.on {
  background: var(--device-on-bg);
  border-color: var(--device-on-border);
}

.device-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.device-icon {
  font-size: 20px;
  line-height: 1;
}

.toggle {
  width: 28px;
  height: 16px;
  border-radius: 8px;
  background: var(--toggle-off-bg);
  position: relative;
  display: block;
}

.toggle::after {
  content: '';
  position: absolute;
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--toggle-knob);
  top: 3px;
  left: 3px;
}

.toggle.on {
  background: var(--toggle-on-bg);
}

.toggle.on::after {
  left: 15px;
}

.device-name {
  font-size: 11px;
  font-weight: 500;
  color: var(--device-name);
  line-height: 1.2;
}

.device-value {
  font-size: 13px;
  font-weight: 700;
  color: var(--device-value-off);
}

.device-card.on .device-value {
  color: var(--device-value-on);
}

.panel-footer {
  background: var(--footer-bg);
  border-radius: 10px;
  padding: 10px 16px;
  display: flex;
  justify-content: space-between;
}

.stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.stat-label {
  font-size: 11px;
  color: var(--stat-label);
  font-weight: 500;
}

.stat-value {
  font-size: 13px;
  font-weight: 700;
  color: var(--stat-value);
}
